"use client"

import { useDraggable } from "@dnd-kit/core"
import { CSS } from "@dnd-kit/utilities"
import { Badge } from "@/components/ui/badge"
import { Card } from "@/components/ui/card"
import type { Task, TaskPriority, TaskStatus } from "@/types"
import { Calendar, Clock, AlertCircle, User, GripVertical } from "lucide-react"
import { format } from "date-fns"
import { cn } from "@/lib/utils"

interface TaskCardProps {
  task: Task
  onClick?: () => void
  isLocked?: boolean
  lockedBy?: string
  isDragOverlay?: boolean
  targetStatus?: TaskStatus | null
  isRecentlyMoved?: boolean
}

const priorityColors: Record<TaskPriority, string> = {
  low: "bg-gray-100 text-gray-700",
  medium: "bg-blue-100 text-blue-700",
  high: "bg-orange-100 text-orange-700",
  critical: "bg-red-100 text-red-700",
}

const statusCardColors: Record<TaskStatus, string> = {
  backlog: "border-l-gray-400",
  todo: "border-l-blue-400",
  in_progress: "border-l-yellow-400",
  review: "border-l-purple-400",
  done: "border-l-green-400",
}

const statusCardBgColors: Record<TaskStatus, string> = {
  backlog: "bg-gray-50",
  todo: "bg-blue-50",
  in_progress: "bg-yellow-50",
  review: "bg-purple-50",
  done: "bg-green-50",
}

export function TaskCard({ 
  task, 
  onClick, 
  isLocked, 
  lockedBy, 
  isDragOverlay,
  targetStatus,
  isRecentlyMoved
}: TaskCardProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    isDragging,
  } = useDraggable({ 
    id: task._id, 
    disabled: isLocked,
    data: { task }
  })

  const style = transform ? {
    transform: CSS.Translate.toString(transform),
  } : undefined

  const isBlocked = task.blocked_by && task.blocked_by.length > 0
  
  // Determine which status color to show
  const displayStatus = isDragOverlay && targetStatus ? targetStatus : task.status

  return (
    <Card
      ref={!isDragOverlay ? setNodeRef : undefined}
      style={style}
      className={cn(
        "p-3 mb-2 transition-all duration-300 border-l-4",
        statusCardColors[displayStatus],
        // Add background color based on status
        isDragOverlay && targetStatus && targetStatus !== task.status && statusCardBgColors[targetStatus],
        // Recently moved animation
        isRecentlyMoved && "animate-pulse ring-2 ring-offset-2",
        isRecentlyMoved && task.status === "backlog" && "ring-gray-400",
        isRecentlyMoved && task.status === "todo" && "ring-blue-400",
        isRecentlyMoved && task.status === "in_progress" && "ring-yellow-400",
        isRecentlyMoved && task.status === "review" && "ring-purple-400",
        isRecentlyMoved && task.status === "done" && "ring-green-400",
        // Drag states
        isDragging && "opacity-40 shadow-sm",
        isDragOverlay && "shadow-2xl rotate-2 scale-105 cursor-grabbing",
        !isDragging && !isDragOverlay && "hover:shadow-md",
        isLocked && "opacity-70 cursor-not-allowed",
        isBlocked && "border-l-red-500"
      )}
      onClick={!isDragging ? onClick : undefined}
    >
      <div className="space-y-2">
        <div className="flex items-start gap-2">
          {/* Drag handle */}
          <div 
            {...attributes}
            {...listeners}
            className={cn(
              "flex-shrink-0 cursor-grab active:cursor-grabbing p-0.5 -ml-1 rounded hover:bg-gray-100 transition-colors",
              isLocked && "cursor-not-allowed opacity-50"
            )}
            onClick={(e) => e.stopPropagation()}
          >
            <GripVertical className="h-4 w-4 text-gray-400" />
          </div>
          
          <div className="flex-1 min-w-0">
            <div className="flex items-start justify-between gap-2">
              <h4 className="font-medium text-sm line-clamp-2">{task.title}</h4>
              <Badge className={cn("shrink-0 text-xs", priorityColors[task.priority])}>
                {task.priority}
              </Badge>
            </div>
          </div>
        </div>

        {task.description && (
          <p className="text-xs text-gray-500 line-clamp-2 ml-5">{task.description}</p>
        )}

        <div className="flex items-center gap-3 text-xs text-gray-500 ml-5">
          {task.due_date && (
            <div className="flex items-center gap-1">
              <Calendar className="h-3 w-3" />
              {format(new Date(task.due_date), "MMM d")}
            </div>
          )}
          {task.time_estimate_hours && (
            <div className="flex items-center gap-1">
              <Clock className="h-3 w-3" />
              {task.time_estimate_hours}h
            </div>
          )}
          {isBlocked && (
            <div className="flex items-center gap-1 text-red-500">
              <AlertCircle className="h-3 w-3" />
              Blocked
            </div>
          )}
        </div>

        {task.assignee_details && task.assignee_details.length > 0 && (
          <div className="flex items-center gap-1 ml-5">
            {task.assignee_details.slice(0, 3).map((user) => (
              <div
                key={user._id}
                className="w-6 h-6 rounded-full bg-blue-500 text-white flex items-center justify-center text-xs"
                title={user.name}
              >
                {user.name?.charAt(0).toUpperCase()}
              </div>
            ))}
            {task.assignee_details.length > 3 && (
              <span className="text-xs text-gray-500">
                +{task.assignee_details.length - 3}
              </span>
            )}
          </div>
        )}

        {isLocked && lockedBy && (
          <div className="flex items-center gap-1 text-xs text-orange-600 ml-5">
            <User className="h-3 w-3" />
            Being edited by {lockedBy}
          </div>
        )}
      </div>
    </Card>
  )
}
