"use client"

import { useEffect, useState } from "react"
import { useParams } from "next/navigation"
import { useStore } from "@/store"
import { api } from "@/lib/api"
import { KanbanBoard } from "@/components/task/KanbanBoard"
import { TaskModal } from "@/components/task/TaskModal"
import { CreateTaskModal } from "@/components/task/CreateTaskModal"
import type { Task, TaskStatus } from "@/types"
import { Users } from "lucide-react"

export default function ProjectPage() {
  const params = useParams()
  const projectId = params.projectId as string
  const { 
    currentProject, setCurrentProject, 
    loadTasks, addTask, updateTask, removeTask,
    joinProject, leaveProject, connectedUsers
  } = useStore()
  
  const [selectedTask, setSelectedTask] = useState<Task | null>(null)
  const [createModalStatus, setCreateModalStatus] = useState<TaskStatus | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadProject()
    return () => {
      if (projectId) {
        leaveProject(projectId)
      }
    }
  }, [projectId])

  const loadProject = async () => {
    setLoading(true)
    try {
      const { project } = await api.getProject(projectId)
      setCurrentProject(project)
      await loadTasks(projectId)
      joinProject(projectId)
    } catch (error) {
      console.error("Failed to load project:", error)
    } finally {
      setLoading(false)
    }
  }

  const handleTaskClick = (task: Task) => {
    setSelectedTask(task)
  }

  const handleAddTask = (status: TaskStatus) => {
    setCreateModalStatus(status)
  }

  const handleTaskCreated = (task: Task) => {
    // addTask already handles duplicates, so this is safe to call
    // even if socket also emits 'task_created'
    addTask(task)
  }

  const handleTaskUpdated = (task: Task) => {
    updateTask(task._id, task)
    setSelectedTask(null)
  }

  const handleTaskDeleted = (taskId: string) => {
    removeTask(taskId)
    setSelectedTask(null)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="h-full flex flex-col">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h1 className="text-2xl font-bold">{currentProject?.name}</h1>
          {currentProject?.description && (
            <p className="text-gray-600">{currentProject.description}</p>
          )}
        </div>
        <div className="flex items-center gap-2">
          {connectedUsers.length > 0 && (
            <div className="flex items-center gap-1 text-sm text-gray-500">
              <Users className="h-4 w-4" />
              {connectedUsers.length} online
            </div>
          )}
          <div className="flex -space-x-2">
            {connectedUsers.slice(0, 5).map((user) => (
              <div
                key={user._id}
                className="w-8 h-8 rounded-full bg-green-500 text-white flex items-center justify-center text-sm border-2 border-white"
                title={user.name}
              >
                {user.name?.charAt(0).toUpperCase()}
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-hidden">
        <KanbanBoard onTaskClick={handleTaskClick} onAddTask={handleAddTask} />
      </div>

      {selectedTask && (
        <TaskModal
          task={selectedTask}
          projectId={projectId}
          onClose={() => setSelectedTask(null)}
          onUpdate={handleTaskUpdated}
          onDelete={handleTaskDeleted}
        />
      )}

      {createModalStatus && (
        <CreateTaskModal
          projectId={projectId}
          initialStatus={createModalStatus}
          onClose={() => setCreateModalStatus(null)}
          onCreate={handleTaskCreated}
        />
      )}
    </div>
  )
}
